import logo from './logo.svg';
import './App.css';

function App() {
  return (
    <div className="App">
      <div className="app-container">
      {/* 1. The Header stays at the top */}
      <Navbar />

      <div className="main-layout">
        {/* 2. The Sidebar stays on the left */}
        <Sidebar />

        {/* 3. This is where your Dashboard, Patients, etc. will appear */}
        <main className="content-area">
          <h1>Dashboard Overview</h1>
          <p>Welcome back, Dr. Alexander.</p>
          {/* We will put the Stat Cards here next */}
        </main>
      </div>
    </div>
    </div>
  );
}

export default App;
